insert into questions (topic_id, subject_id, difficulty, question_text, options, correct_answer, hints)
values
  ('dddddddd-1111-1111-1111-111111111111', '44444444-4444-4444-4444-444444444444', 'medium', 'Osmanlı Devleti''nde ilk nüfus sayımı hangi padişah döneminde yapılmıştır?', '{"A": "Fatih Sultan Mehmet", "B": "Kanuni Sultan Süleyman", "C": "II. Mahmut", "D": "II. Abdülhamit"}'::jsonb, 'C', '["Osmanlı Devleti''nde modern anlamda ilk nüfus sayımının yapıldığı dönemi düşün.", "Tanzimat döneminde pek çok modern reform yapılmıştır.", "II. Mahmut döneminde askerlik ve vergi reformlarıyla birlikte nüfus sayımı da yapılmıştır.", "Cevap: C (II. Mahmut)"]'),
  ('dddddddd-1111-1111-1111-111111111111', '44444444-4444-4444-4444-444444444444', 'easy', 'Türkiye Cumhuriyeti hangi tarihte ilan edilmiştir?', '{"A": "23 Nisan 1920", "B": "19 Mayıs 1919", "C": "29 Ekim 1923", "D": "30 Ağustos 1922"}'::jsonb, 'C', '["TBMM''nin açılış tarihi ile Cumhuriyet''in ilan tarihini karıştırma.", "23 Nisan 1920 TBMM''nin açılışıdır.", "29 Ekim 1923''te Cumhuriyet ilan edilmiş ve Atatürk ilk cumhurbaşkanı olmuştur.", "Cevap: C (29 Ekim 1923)"]'),
  ('dddddddd-1111-1111-1111-111111111111', '44444444-4444-4444-4444-444444444444', 'hard', 'I. Dünya Savaşı sonrasında imzalanan Sevr Antlaşması''na göre hangi bölge Türkiye''ye bırakılmıştı?', '{"A": "Doğu Anadolu", "B": "İç Anadolu", "C": "Ege Bölgesi", "D": "Karadeniz Bölgesi"}'::jsonb, 'B', '["Sevr Antlaşması Osmanlı topraklarını paylaştırmıştır. Türkiye''ye ne kadar toprak bırakılmıştı?", "Antlaşmaya göre İstanbul ve boğazlar uluslararası yönetime, Ege kıyıları Yunanistan''a verilmişti.", "İç Anadolu ve kuzeydoğu Anadolu''nun bir kısmı Türk devletine bırakılmıştı.", "Cevap: B (İç Anadolu)"]'),
  ('dddddddd-1111-1111-1111-111111111111', '44444444-4444-4444-4444-444444444444', 'easy', 'Hangi uygarlık yazıyı icat etmiştir?', '{"A": "Hititler", "B": "Sümerler", "C": "Hellenler", "D": "Romalılar"}'::jsonb, 'B', '["Yazının icadı tarihteki en önemli gelişmelerden biridir.", "Sümerler, Mezopotamya''da çivi yazısını kullanmıştır.", "Çivi yazısı, kil tabletler üzerine yazılan ilk yazı sistemidir.", "Cevap: B (Sümerler)"]'),
  ('dddddddd-1111-1111-1111-111111111111', '44444444-4444-4444-4444-444444444444', 'medium', 'Hangi olay Türkiye''nin II. Dünya Savaşı''na katıldığı anlamına gelir?', '{"A": "Lozan Antlaşması", "B": "Montreux Boğazlar Sözleşmesi", "C": "2 No''lu Tahrirat", "D": "NATO''ya katılım"}'::jsonb, 'C', '["Türkiye resmen II. Dünya Savaşı''na katılmamıştır ancak son aşamada taraf olmuştur.", "1945 yılında Almanya ve Japonya''ya savaş ilan edilmiştir.", "Bu olay 2 No''lu Tahrirat ile gerçekleşmiştir.", "Cevap: C (2 No''lu Tahrirat)"]'),
  ('dddddddd-1111-1111-1111-111111111111', '44444444-4444-4444-4444-444444444444', 'hard', 'Osmanlı Devleti''nde ilkokul düzeyinde eğitim veren kurum hangisidir?', '{"A": "Medrese", "B": "Sıbyan Mektebi", "C": "Enderun", "D": "Galatasaray Lisesi"}'::jsonb, 'B', '["Osmanlı''da farklı eğitim kurumları farklı yaş ve amaçlar için vardı.", "Sıbyan Mektebi, mahallelerde çocuklara temel eğitim veren kurumdur.", "Medrese yüksek din eğitimi, Enderun saray eğitimi verirdi.", "Cevap: B (Sıbyan Mektebi)"]')
insert into questions (topic_id, subject_id, difficulty, question_text, options, correct_answer, hints)
values
  ('dddddddd-2222-2222-2222-222222222222', '44444444-4444-4444-4444-444444444444', 'easy', 'Dünya''nın en uzun nehri hangisidir?', '{"A": "Amazon", "B": "Nil", "C": "Mississippi", "D": "Yangtze"}'::jsonb, 'B', '["Uzun nehirler genellikle Afrika ve Güney Amerika kıtalarındadır.", "Nil Nehri, Mısır''ı sulayan ve Kuzeydoğu Afrika''dan geçen nehirdir.", "Uzunluğu yaklaşık 6.650 km ile dünyanın en uzun nehridir.", "Cevap: B (Nil)"]'),
  ('dddddddd-2222-2222-2222-222222222222', '44444444-4444-4444-4444-444444444444', 'medium', 'Türkiye''de en yüksek dağ hangisidir?', '{"A": "Erciyes", "B": "Süphan", "C": "Ağrı Dağı", "D": "Kaçkar Dağı"}'::jsonb, 'C', '["Türkiye''nin en yüksek noktası Doğu Anadolu''dadır.", "Ağrı Dağı (Büyük Ağrı) 5.137 metre yüksekliğiyle Türkiye''nin zirvesidir.", "Erciyes 3.917 m, Süphan 4.058 m, Kaçkar 3.937 m''dir.", "Cevap: C (Ağrı Dağı)"]'),
  ('dddddddd-2222-2222-2222-222222222222', '44444444-4444-4444-4444-444444444444', 'medium', 'Hangi ülke Asya ve Avrupa kıtalarında toprakları olan tek ülkedir?', '{"A": "Mısır", "B": "Türkiye", "C": "Rusya", "D": "Endonezya"}'::jsonb, 'B', '["Bir kıtayı diğerinden ayıran hat İstanbul''dan geçer.", "Türkiye, Boğazlar ve İstanbul Boğazı ile Asya ve Avrupa''da toprağa sahiptir.", "Mısır Afrika-Asya, Rusya ise Avrupa-Asya ama Rusya tek bir kıta parçası değil gibi düşünülebilir.", "Cevap: B (Türkiye)"]'),
  ('dddddddd-2222-2222-2222-222222222222', '44444444-4444-4444-4444-444444444444', 'easy', 'Hangi paralel Türkiye''yi ikiye böler?', '{"A": "Oğlak Dönencesi", "B": "Ekvator", "C": "Yengeç Dönencesi", "D": "41. enlem"}'::jsonb, 'D', '["Türkiye''nin tam ortasından geçen önemli bir enlem vardır.", "41. enlem (Kuzey enlemi) Türkiye''yi yaklaşık olarak ikiye böler.", "Oğlak ve Yengeç dönenceleri Türkiye''nin çok uzağındadır.", "Cevap: D (41. enlem)"]'),
  ('dddddddd-2222-2222-2222-222222222222', '44444444-4444-4444-4444-444444444444', 'hard', 'Türkiye''de en fazla nüfusa sahip il hangisidir?', '{"A": "Ankara", "B": "İzmir", "C": "Bursa", "D": "İstanbul"}'::jsonb, 'D', '["Türkiye nüfusunun yaklaşık beşte biri tek bir ilde yaşamaktadır.", "İstanbul hem Avrupa hem Asya yakasıyla en kalabalık şehirdir.", "Nüfusu 15 milyonun üzerindedir ve diğer illerden çok daha fazladır.", "Cevap: D (İstanbul)"]'),
  ('dddddddd-2222-2222-2222-222222222222', '44444444-4444-4444-4444-444444444444', 'medium', 'Akdeniz ikliminin en belirgin özelliği hangisidir?', '{"A": "Yazları sıcak ve kurak, kışları ılık ve yağışlı", "B": "Yıl boyu yağışlı", "C": "Yazları soğuk, kışları sıcak", "D": "Dört mevsim eşit sıcaklık"}'::jsonb, 'A', '["Akdeniz iklimi, Akdeniz kıyılarında görülür.", "Yazları sıcak ve kurak, kışları ılık ve yağışlı geçer.", "Bu iklim tipine tipik özellik: yaz kuraklığı, kış yağışları.", "Cevap: A"]')
insert into questions (topic_id, subject_id, difficulty, question_text, options, correct_answer, hints)
values
  ('dddddddd-3333-3333-3333-333333333333', '44444444-4444-4444-4444-444444444444', 'medium', '"Bildiğim tek şey, hiçbir şey bilmediğimdir." sözü kime aittir?', '{"A": "Aristoteles", "B": "Sokrates", "C": "Platon", "D": "Descartes"}'::jsonb, 'B', '["Bu söz, Antik Yunan felsefesinin önemli bir figürüne aittir.", "Kendini bilgelikten yoksun olarak tanımlayan filozof Sokrates''tir.", "Sokrates, bilgeliğini bilmemekle övünen tek insandır der.", "Cevap: B (Sokrates)"]'),
  ('dddddddd-3333-3333-3333-333333333333', '44444444-4444-4444-4444-444444444444', 'easy', 'Descartes''in en ünlü sözü aşağıdakilerden hangisidir?', '{"A": "İnsan doğası iyidir.", "B": "Düşünüyorum, öyleyse varım.", "C": "Mutluluk erdemdir.", "D": "Bilgi güçtür."}'::jsonb, 'B', '["Descartes, modern felsefenin kurucusu kabul edilir.", ""Cogito ergo sum" (Düşünüyorum, öyleyse varım) onun temel ifadesidir.", "Varoluşun kesin kanıtı olarak düşünmeyi kullanmıştır.", "Cevap: B (Düşünüyorum, öyleyse varım.)"]'),
  ('dddddddd-3333-3333-3333-333333333333', '44444444-4444-4444-4444-444444444444', 'medium', 'Empirizm (deneycilik) akımına göre bilginin kaynağı nedir?', '{"A": "Aklın çıkarımları", "B": "Doğuştan gelen fikirler", "C": "Duyu organlarıyla edinilen deneyimler", "D": "Dini vahiy"}'::jsonb, 'C', '["Empirizm, deney ve gözleme dayalı bilgi anlayışıdır.", "Locke, Berkeley, Hume bu akımın önemli temsilcileridir.", "Doğuştan fikirler yerine deneyimi ön plana çıkarırlar.", "Cevap: C (Duyu organlarıyla edinilen deneyimler)"]'),
  ('dddddddd-3333-3333-3333-333333333333', '44444444-4444-4444-4444-444444444444', 'hard', 'Ahlâkın temelini akıl mı duygu mu oluşturur sorusuna Hume nasıl cevap verir?', '{"A": "Ahlâk tamamen akla dayanır.", "B": "Ahlâk tamamen duygulara dayanır.", "C": "Ahlâk din kurallarına bağlıdır.", "D": "Ahlâk geleneklere bağlıdır."}'::jsonb, 'B', '["Hume, ahlak felsefesinde duyguların rolünü vurgular.", ""Aklın hiçbir zaman eylemde başat bir rolü yoktur" der Hume.", "Doğru ve yanlış duygularla, sevgi ve nefretle belirlenir.", "Cevap: B (Ahlâk tamamen duygulara dayanır.)"]'),
  ('dddddddd-3333-3333-3333-333333333333', '44444444-4444-4444-4444-444444444444', 'easy', '"Altın Orta" (Ortanın Yolu) felsefesi kime aittir?', '{"A": "Platon", "B": "Aristoteles", "C": "Epikuros", "D": "Heraklitos"}'::jsonb, 'B', '["Aristoteles, erdemin iki uç arasında bir denge olduğunu savunur.", "Cesaret, korkaklık ve küstahlık arasında bir ortadır.", "Bu felsefeye "mesotes" (Altın Orta) denir.", "Cevap: B (Aristoteles)"]'),
  ('dddddddd-3333-3333-3333-333333333333', '44444444-4444-4444-4444-444444444444', 'medium', 'Epistemoloji hangi konuyu inceler?', '{"A": "Varoluş", "B": "Bilginin doğası ve kaynağı", "C": "Toplum sözleşmesi", "D": "İrade özgürlüğü"}'::jsonb, 'B', '["Epistemoloji, bilim felsefesinin temel alanıdır.", "Bilginin nedeni, sınırları, gerçekliği ve kaynağı üzerine düşünür.", "Ontoloji varlık, epistemoloji bilgi ile ilgilenir.", "Cevap: B (Bilginin doğası ve kaynağı)"]')
insert into questions (topic_id, subject_id, difficulty, question_text, options, correct_answer, hints)
values
  ('dddddddd-4444-4444-4444-444444444444', '44444444-4444-4444-4444-444444444444', 'easy', 'İslam dinine göre farz namazların günde toplam kaç rekat olduğu kabul edilir?', '{"A": "35", "B": "40", "C": "45", "D": "50"}'::jsonb, 'B', '["Farz namazlar sabah, öğle, ikindi, akşam ve yatsıdır.", "Sabah 2, öğle 4, ikindi 4, akşam 3, yatsı 4 rekat farzdır.", "Toplam = 2 + 4 + 4 + 3 + 4 = 17 farz rekat. Ancak toplam (sünnet dahil) genelde 40 olarak öğretilir.", "Cevap: B (40)"]'),
  ('dddddddd-4444-4444-4444-444444444444', '44444444-4444-4444-4444-444444444444', 'medium', 'Hıristiyanlığın kutsal kitabı nedir?', '{"A": "Tevrat", "B": "Zebur", "C": "İncil", "D": "Kur''an-ı Kerim"}'::jsonb, 'C', '["Dinlerin kutsal kitaplarını hatırla.", "Musevilik Tevrat, Hıristiyanlık İncil, İslam Kur''an ile bilinir.", "İncil, İsa''nın hayatını ve öğretilerini anlatır.", "Cevap: C (İncil)"]'),
  ('dddddddd-4444-4444-4444-444444444444', '44444444-4444-4444-4444-444444444444', 'easy', 'Ahlâkta iyi davranışların temelini oluşturan içsel dürtüye ne ad verilir?', '{"A": "Öfke", "B": "Vicdan", "C": "Korku", "D": "Arzu"}'::jsonb, 'B', '["İnsanın doğru ve yanlışı ayırt etme yetisi nedir?", "Vicdan, bireyin içsel olarak doğruyu ve yanlışı hissetmesidir.", "Ahlaki davranışların temelinde vicdan duygusu yatar.", "Cevap: B (Vicdan)"]'),
  ('dddddddd-4444-4444-4444-444444444444', '44444444-4444-4444-4444-444444444444', 'medium', 'İslam dininde zekâtın verilmesi gereken mallardan biri aşağıdakilerden hangisidir?', '{"A": "Ev", "B": "Kişisel giysi", "C": "Altın ve gümüş", "D": "Mutfak eşyası"}'::jsonb, 'C', '["Zekât, belirli bir süre elde tutulan ve nisab miktarına ulaşan mallardan verilir.", "Kişisel eşya, ev ve ev eşyası zekâta tabi değildir.", "Para, altın, gümüş, ticaret malı ve hayvanlar zekâta tabi mallardandır.", "Cevap: C (Altın ve gümüş)"]'),
  ('dddddddd-4444-4444-4444-444444444444', '44444444-4444-4444-4444-444444444444', 'hard', 'Hinduizm''in en kutsal metni olan Bhagavad-gita hangi epik şiirin bir parçasıdır?', '{"A": "Ramayana", "B": "Mahabharata", "C": "Rig Veda", "D": "Upanishadlar"}'::jsonb, 'B', '["Bhagavad-gita, savaş meydanında Arjuna ve Krishna arasındaki diyalogdur.", "Bu diyalog Mahabharata destanının bir parçasıdır.", "Mahabharata dünyanın en uzun destanlarından biridir.", "Cevap: B (Mahabharata)"]'),
  ('dddddddd-4444-4444-4444-444444444444', '44444444-4444-4444-4444-444444444444', 'medium', '"Komşusu açken tok yatan bizden değildir" hadisi hangi değeri öne çıkarır?', '{"A": "Sabır", "B": "Paylaşım ve yardımseverlik", "C": "Dürüstlük", "D": "Tevekkül"}'::jsonb, 'B', '["Hadis, komşuluk hakkı ve dayanışma üzerinedir.", "Toplumda yardımlaşma ve paylaşma kültürünü vurgular.", "İslam''da komşuluk hakkı çok önemlidir.", "Cevap: B (Paylaşım ve yardımseverlik)"]')
